#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

import argparse
import json
import sys
from pathlib import Path

from wiki_common import PROJECT_SETTINGS_REL, WIKI_RESEARCH_PHASES, load_wiki_research_max_pages



def _configure_stdio() -> None:
    for stream in (sys.stdout, sys.stderr):
        if not hasattr(stream, "reconfigure"):
            continue
        try:
            stream.reconfigure(encoding="utf-8", errors="replace", newline="\n")
        except (OSError, ValueError):
            pass

def main() -> int:
    _configure_stdio()
    parser = argparse.ArgumentParser(description="Inspect wiki research settings.")
    parser.add_argument("project_root", help="Target project root")
    parser.add_argument("--phase", choices=WIKI_RESEARCH_PHASES, help="Return only the configured/default maxWikiPages for this phase")
    parser.add_argument("--show-policy", action="store_true", help="Include normalized maxWikiPages policy in output")
    args = parser.parse_args()

    try:
        project_root = Path(args.project_root).resolve()
        settings_path = project_root / PROJECT_SETTINGS_REL
        limits = load_wiki_research_max_pages(project_root)
        payload = {
            "settingsPath": settings_path.as_posix(),
            "status": "configured" if settings_path.is_file() else "not_configured",
        }
        if args.phase:
            value = limits[args.phase]
            payload.update({
                "phase": args.phase,
                "maxWikiPages": value,
                "unlimited": value is None,
            })
        if args.show_policy or not args.phase:
            payload["policy"] = {
                phase: {"maxWikiPages": value, "unlimited": value is None}
                for phase, value in limits.items()
            }
        print(json.dumps(payload, ensure_ascii=False, indent=2, sort_keys=True))
        return 0
    except ValueError as exc:
        print(f"Error: {exc}", file=sys.stderr)
        return 1


if __name__ == "__main__":
    raise SystemExit(main())
